import { useState } from 'react';
import * as Icons from '../icons';

const Dashboard = () => {
  return (
    <div>
      {/* ... other components ... */}
      <HabitRow
        title="Exercise"
        triggerType="check"
        triggerValue={1}
      />
      {/* ... other components ... */}
    </div>
  );
};

interface HabitRowProps {
  title: string;
  triggerType: 'check' | 'count' | 'time' | 'bool';
  triggerValue: number;
}

const HabitRow: React.FC<HabitRowProps> = ({ title, triggerType, triggerValue }) => {
  const [isCompleted, setIsCompleted] = useState<boolean>(false);

  const getTriggerText = () => {
    switch (triggerType) {
      case 'check':
        return 'Check';
      case 'count':
        return `Count ${triggerValue}`;
      case 'time':
        return `Time ${triggerValue}`;
      case 'bool':
        return 'Complete';
      default:
        return '';
    }
  };

  return (
    <div className="flex items-center justify-between py-2 border-b border-gray-200">
      <div className="flex items-center space-x-4">
        <div className="flex items-center space-x-2">
          {/* <button className="w-8 h-8 rounded-full bg-navy-800 text-white flex items-center justify-center">
            {isCompleted ? <Icons.CheckCircle2 size={24} fill="currentColor" /> : <Icons.Plus size={24} fill="currentColor" />}
          </button> */}
          <button
            onClick={() => setIsCompleted(!isCompleted)}
            className={`w-8 h-8 flex items-center justify-center rounded-full  
          ${isCompleted
                ? 'bg-green-400 text-white scale-105 rotate-[-3deg] shadow-inner animate-scale-in'
                : 'bg-ios-input text-slate-400 hover:bg-navy-900 hover:text-white hover:shadow-md'
              }
        `}
          >
            {isCompleted ? (
              <Icons.CheckCircle2 size={24} className="text-white" stroke="rgb(34, 197, 94)" />
            ) : (
              <div className="w-5 h-5 rounded-full border-[2.5px] border-current opacity-60" />
            )}
          </button>
          <div>
            <h3 className="font-medium text-lg">{title}</h3>
            <p className="text-sm text-gray-500">{getTriggerText()}</p>
          </div>
        </div>
      </div>
    </div>
  );
};

export default Dashboard;
```

